namespace NotificationsApp.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = [];
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(
        [
            new() { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
            new() { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
            new() { Id = _nextId++, Message = "New feature available: dark mode.", Timestamp = DateTime.UtcNow.AddMinutes(-1) },
        ]);

        // Simulate new notifications arriving over time.
        _ = GenerateNotificationsAsync();
    }

    /// <summary>Returns all notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public Task<List<Notification>> GetNotificationsAsync(int sinceId = 0)
    {
        lock (_lock)
        {
            var result = _notifications.Where(n => n.Id > sinceId).ToList();
            return Task.FromResult(result);
        }
    }

    private async Task GenerateNotificationsAsync()
    {
        var messages = new[]
        {
            "Someone liked your post.",
            "You have a new follower.",
            "Server maintenance scheduled.",
            "Your report is ready to download.",
            "A comment was added to your thread.",
            "Weekly digest is available.",
        };

        var rng = new Random();

        while (true)
        {
            await Task.Delay(TimeSpan.FromSeconds(rng.Next(6, 15)));

            lock (_lock)
            {
                _notifications.Add(new Notification
                {
                    Id = _nextId++,
                    Message = messages[rng.Next(messages.Length)],
                    Timestamp = DateTime.UtcNow,
                });
            }
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> notifications = [];
    private CancellationTokenSource? _cts;

    // Persist across prerender → interactive so we don't re-fetch.
    [PersistentState]
    public List<Notification>? PersistedNotifications { get; set; }

    [PersistentState]
    public int? PersistedMaxId { get; set; }

    private int _maxId;

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we only hit the service if state wasn't restored from prerender.
        PersistedNotifications ??= await NotificationSvc.GetNotificationsAsync();
        PersistedMaxId ??= PersistedNotifications.Count > 0
            ? PersistedNotifications.Max(n => n.Id)
            : 0;

        notifications = PersistedNotifications;
        _maxId = PersistedMaxId.Value;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender is NOT called during prerender — only after the
            // interactive runtime attaches, so the polling loop is safe here.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var newer = await NotificationSvc.GetNotificationsAsync(_maxId);
            if (newer.Count > 0)
            {
                notifications.AddRange(newer);
                _maxId = newer.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

